import React from "react";
import { useSelector } from "react-redux";

function InteractionForm() {
  const form = useSelector((state) => state.form);

  const sentimentEmoji = { positive: "😊", neutral: "😐", negative: "😞" };

  // Dynamic sentiment class
  const sentimentClass = form.sentiment ? form.sentiment : "neutral";

  return (
    <div>
      <h2>Log HCP Interaction</h2>

      <div className="field-card">
        <label>HCP Name</label>
        <input value={form.hcp_name || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Interaction Type</label>
        <input value={form.interaction_type || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Date</label>
        <input value={form.date?.split(" ")[0] || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Time</label>
        <input value={form.time?.split(" ")[1] || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Topics Discussed</label>
        <textarea value={form.topics || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Outcomes</label>
        <textarea value={form.outcomes || ""} readOnly />
      </div>

      <div className="field-card">
        <label>Follow Up</label>
        <textarea value={form.followup || ""} readOnly />
      </div>

      {form.sentiment && (
        <div className={`sentiment ${sentimentClass}`}>
          {sentimentEmoji[form.sentiment]} {form.sentiment}
        </div>
      )}
    </div>
  );
}

export default InteractionForm;
